# PyPI package name -> Flox catalog pkg-path
# Format: pip_name<TAB>nixpkgs_path<TAB>notes (optional)
# Used when parsing `pip install` / `uv pip install` commands
#
# Sentinels:
#   _skip_    = included with python3, ignore entirely
#   _project_ = belongs in project graph (pyproject.toml / uv.lock), not Flox [install]
#
# Classification calculus (contract scope):
#   [install] = CLI tools invoked from shell/CI/hooks, or native-extension packages
#               that couple to system libraries (ABI, headers, pg_config, etc.)
#   _project_ = libraries imported by project code whose compatibility is confined
#               within the Python dependency graph

# Skip (included with python3)
pip	_skip_
setuptools	_skip_
wheel	_skip_

# Package managers / build tools -> Flox [install]
uv	uv
pipenv	pipenv
poetry	poetry
hatch	hatch
pdm	python313Packages.pdm
tox	python313Packages.tox
nox	python313Packages.nox
flit	python313Packages.flit-core
twine	python313Packages.twine
build	python313Packages.build

